function activate(context: vscode.ExtensionContext) {
  console.log('CodeAtlas extension activating...');

  // Get workspace root
  const workspaceRoot = vscode.workspace.workspaceFolders?.[0]?.uri.fsPath;
  if (!workspaceRoot) {
    vscode.window.showWarningMessage('CodeAtlas: No workspace folder found');
    return;
  }

  // Initialize providers
  structureProvider = new StructureTreeProvider();
  layersProvider = new LayersTreeProvider();
  graphProvider = new GraphWebviewProvider(context.extensionUri);
  hoverProvider = new CodeAtlasHoverProvider();
  codeLensProvider = new CodeAtlasCodeLensProvider();

  // Initialize store (async) and set on providers when ready
  const dbPath = path.join(workspaceRoot, '.codeatlas', 'db.sqlite');
  SQLiteStore.create({ dbPath }).then(initializedStore => {
    store = initializedStore;
    structureProvider.setStore(store, workspaceRoot);
    layersProvider.setStore(store);
    hoverProvider.setStore(store);
    codeLensProvider.setStore(store);
  }).catch(err => {
    vscode.window.showErrorMessage(`CodeAtlas: Failed to initialize database: ${err}`);
  });

  // Register TreeView providers
  vscode.window.registerTreeDataProvider('codeatlas.structureView', structureProvider);
  vscode.window.registerTreeDataProvider('codeatlas.layersView', layersProvider);

  // Register WebviewView provider
  context.subscriptions.push(
    vscode.window.registerWebviewViewProvider(GraphWebviewProvider.viewType, graphProvider)
  );

  // Register Hover provider
  context.subscriptions.push(
    vscode.languages.registerHoverProvider('*', hoverProvider)
  );

  // Register CodeLens provider
  context.subscriptions.push(
    vscode.languages.registerCodeLensProvider('*', codeLensProvider)
  );

  // Register commands
  registerCommands(context, workspaceRoot);

  // Watch for file changes
  const watcher = vscode.workspace.createFileSystemWatcher('**/*.{ts,js,py,go,rs,java}');
  watcher.onDidChange(() => {
    codeLensProvider.refresh();
  });
  context.subscriptions.push(watcher);

  console.log('CodeAtlas extension activated');
}

function registerCommands(context: vscode.ExtensionContext, workspaceRoot: string) {
  // Scan command
  context.subscriptions.push(
    vscode.commands.registerCommand('codeatlas.scan', async () => {
      await vscode.window.withProgress(
        { location: vscode.ProgressLocation.Notification, title: 'CodeAtlas: Scanning...' },
        async (progress) => {
          try {
            const scanner = new ProjectScanner(store!);
            const result = await scanner.scan({
              projectPath: workspaceRoot,
              onProgress: (current, total, file) => {
                progress.report({
                  message: `${current}/${total}`,
                  increment: (1 / total) * 100,
                });
              },
            });

            vscode.window.showInformationMessage(
              `CodeAtlas: Scanned ${result.filesScanned} files, found ${result.symbolsFound} symbols`
            );

            // Refresh all views
            structureProvider.refresh();
            layersProvider.refresh();
            graphProvider.refreshGraph();
            codeLensProvider.refresh();
          } catch (err) {
            vscode.window.showErrorMessage(`CodeAtlas scan failed: ${err}`);
          }
        }
      );
    })
  );

  // Search command
  context.subscriptions.push(
    vscode.commands.registerCommand('codeatlas.search', async () => {
      const query = await vscode.window.showInputBox({
        prompt: 'Search symbols',
        placeHolder: 'e.g., UserService, handleAuth, create',
      });
      if (!query) return;

      const results = store!.searchSymbols(query, { limit: 20 });
      if (results.length === 0) {
        vscode.window.showInformationMessage(`No symbols found for "${query}"`);
        return;
      }

      const items = results.map(s => ({
        label: `${s.name}`,
        description: `${s.kind} · ${s.layer}`,
        detail: `${s.filePath}:${s.startLine}`,
        symbol: s,
      }));

      const selected = await vscode.window.showQuickPick(items, {
        placeHolder: `Found ${results.length} symbols`,
      });

      if (selected) {
        const uri = vscode.Uri.file(path.join(workspaceRoot, selected.symbol.filePath));
        const doc = await vscode.workspace.openTextDocument(uri);
        await vscode.window.showTextDocument(doc, {
          selection: new vscode.Range(
            selected.symbol.startLine - 1, 0,
            selected.symbol.startLine - 1, 0
          ),
        });
      }
    })
  );

  // Show Graph command
  context.subscriptions.push(
    vscode.commands.registerCommand('codeatlas.showGraph', () => {
      const panel = vscode.window.createWebviewPanel(
        'codeatlas.graph',
        'Code Graph',
        vscode.ViewColumn.Two,
        { enableScripts: true, retainContextWhenHidden: true }
      );
      panel.webview.html = getGraphWebviewHtml();
    })
  );

  // Analyze Impact command
  context.subscriptions.push(
    vscode.commands.registerCommand('codeatlas.analyzeImpact', async () => {
      const editor = vscode.window.activeTextEditor;
      if (!editor) {
        vscode.window.showWarningMessage('No active editor');
        return;
      }

      const selection = editor.document.getText(editor.selection);
      if (!selection) {
        vscode.window.showWarningMessage('Select a symbol name first');
        return;
      }

      const results = store!.searchSymbols(selection, { limit: 5 });
      if (results.length === 0) {
        vscode.window.showInformationMessage(`Symbol "${selection}" not found`);
        return;
      }

      const symbol = results[0];
      const analyzer = new ImpactAnalyzer(store!);
      const impact = analyzer.analyze(symbol.id, 3);

      if (impact) {
        // Show in output channel
        const channel = vscode.window.createOutputChannel('CodeAtlas Impact');
        channel.clear();
        channel.appendLine(impact.summary);
        channel.show();
      }
    })
  );

  // Explain File command
  context.subscriptions.push(
    vscode.commands.registerCommand('codeatlas.explainFile', async () => {
      const editor = vscode.window.activeTextEditor;
      if (!editor) return;

      const filePath = editor.document.uri.fsPath;
      const relativePath = path.relative(workspaceRoot, filePath).replace(/\\/g, '/');
      const symbols = store!.getSymbolsByFile(relativePath);

      if (symbols.length === 0) {
        vscode.window.showInformationMessage('No symbols found in this file');
        return;
      }

      // Show file summary
      const lines = [
        `## ${relativePath}`,
        '',
        `**${symbols.length} symbols found:**`,
        '',
      ];

      for (const s of symbols) {
        lines.push(`- **${s.name}** (${s.kind}, ${s.layer}) @ line ${s.startLine}`);
      }

      const panel = vscode.window.createWebviewPanel(
        'codeatlas.explain',
        `Explain: ${path.basename(filePath)}`,
        vscode.ViewColumn.Two,
        {}
      );
      panel.webview.html = getExplainWebviewHtml(lines.join('\n'));
    })
  );

  // Show Layers command
  context.subscriptions.push(
    vscode.commands.registerCommand('codeatlas.showLayers', async () => {
      const stats = store!.getStats();
      const layers = ['interface', 'business', 'data', 'utility'] as const;

      const lines = [
        '## Architecture Layers',
        '',
        `**${stats.symbols} symbols, ${stats.relationships} relationships, ${stats.files} files**`,
        '',
      ];

      for (const layer of layers) {
        const symbols = store!.getSymbolsByLayer(layer);
        const pct = stats.symbols > 0 ? Math.round((symbols.length / stats.symbols) * 100) : 0;
        lines.push(`### ${layer.toUpperCase()} (${symbols.length} symbols, ${pct}%)`);
        lines.push('');
        for (const s of symbols.slice(0, 10)) {
          lines.push(`- ${s.name} (${s.kind}) @ ${s.filePath}:${s.startLine}`);
        }
        if (symbols.length > 10) {
          lines.push(`- ... and ${symbols.length - 10} more`);
        }
        lines.push('');
      }

      const panel = vscode.window.createWebviewPanel(
        'codeatlas.layers',
        'Architecture Layers',
        vscode.ViewColumn.Two,
        {}
      );
      panel.webview.html = getExplainWebviewHtml(lines.join('\n'));
    })
  );

  // Show Callers
  context.subscriptions.push(
    vscode.commands.registerCommand('codeatlas.showCallers', (symbolId: string) => {
      const callers = store!.getCallers(symbolId);
      const symbol = store!.getSymbol(symbolId);

      const items = callers.map(s => ({
        label: s.name,
        description: `${s.kind} · ${s.layer}`,
        detail: `${s.filePath}:${s.startLine}`,
        symbol: s,
      }));

      vscode.window.showQuickPick(items, {
        placeHolder: `${callers.length} callers of ${symbol?.name ?? symbolId}`,
      }).then(selected => {
        if (selected) {
          const uri = vscode.Uri.file(path.join(workspaceRoot, selected.symbol.filePath));
          vscode.window.showTextDocument(uri, {
            selection: new vscode.Range(
              selected.symbol.startLine - 1, 0,
              selected.symbol.startLine - 1, 0
            ),
          });
        }
      });
    })
  );

  // Show Callees
  context.subscriptions.push(
    vscode.commands.registerCommand('codeatlas.showCallees', (symbolId: string) => {
      const callees = store!.getCallees(symbolId);
      const symbol = store!.getSymbol(symbolId);

      const items = callees.map(s => ({
        label: s.name,
        description: `${s.kind} · ${s.layer}`,
        detail: `${s.filePath}:${s.startLine}`,
        symbol: s,
      }));

      vscode.window.showQuickPick(items, {
        placeHolder: `${callees.length} callees of ${symbol?.name ?? symbolId}`,
      }).then(selected => {
        if (selected) {
          const uri = vscode.Uri.file(path.join(workspaceRoot, selected.symbol.filePath));
          vscode.window.showTextDocument(uri, {
            selection: new vscode.Range(
              selected.symbol.startLine - 1, 0,
              selected.symbol.startLine - 1, 0
            ),
          });
        }
      });
    })
  );
}

function deactivate() {
  if (store) {
    store.close();
  }
}

function getGraphWebviewHtml(): string {
  return `<!DOCTYPE html>
<html>
<head>
  <meta charset="UTF-8">
  <style>
    body { margin: 0; padding: 0; overflow: hidden; }
    #graph { width: 100vw; height: 100vh; }
  </style>
</head>
<body>
  <div id="graph"></div>
  <script src="https://unpkg.com/cytoscape@3.28.0/dist/cytoscape.min.js"></script>
  <script>
    // Graph visualization will be loaded here
    document.getElementById('graph').innerHTML = '<div style="display:flex;align-items:center;justify-content:center;height:100vh;color:#888;">Graph visualization loading...</div>';
  </script>
</body>
</html>`;
}

function getExplainWebviewHtml(markdown: string): string {
  // Simple markdown to HTML conversion
  const html = markdown
    .replace(/^### (.+)$/gm, '<h3>$1</h3>')
    .replace(/^## (.+)$/gm, '<h2>$1</h2>')
    .replace(/^# (.+)$/gm, '<h1>$1</h1>')
    .replace(/\*\*(.+?)\*\*/g, '<strong>$1</strong>')
    .replace(/\*(.+?)\*/g, '<em>$1</em>')
    .replace(/`(.+?)`/g, '<code>$1</code>')
    .replace(/^- (.+)$/gm, '<li>$1</li>')
    .replace(/(<li>.*<\/li>\n?)+/g, '<ul>$&</ul>')
    .replace(/\n\n/g, '<br><br>');

  return `<!DOCTYPE html>
<html>
<head>
  <meta charset="UTF-8">
  <style>
    body {
      font-family: var(--vscode-font-family);
      background: var(--vscode-editor-background);
      color: var(--vscode-editor-foreground);
      padding: 20px;
      line-height: 1.6;
    }
    h1, h2, h3 { margin-top: 16px; margin-bottom: 8px; }
    code {
      background: var(--vscode-textCodeBlock-background);
      padding: 2px 6px;
      border-radius: 4px;
    }
    ul { margin: 8px 0; }
    li { margin: 4px 0; }
  </style>
</head>
<body>
  ${html}
</body>
</html>`;
}

class CodeAtlasCodeLensProvider implements vscode.CodeLensProvider {
  private store: SQLiteStore | null = null;
  private _onDidChangeCodeLenses = new vscode.EventEmitter<void>();
  readonly onDidChangeCodeLenses = this._onDidChangeCodeLenses.event;

  constructor() {}

  setStore(store: SQLiteStore) {
    this.store = store;
    this._onDidChangeCodeLenses.fire();
  }

  refresh() {
    this._onDidChangeCodeLenses.fire();
  }

  provideCodeLenses(document: vscode.TextDocument): vscode.CodeLens[] {
    if (!this.store) return [];

    const lenses: vscode.CodeLens[] = [];
    const filePath = this.getRelativePath(document.uri.fsPath);

    // Get symbols in this file
    const symbols = this.store.getSymbolsByFile(filePath);

    for (const symbol of symbols) {
      // Only show for functions, methods, classes
      if (!['function', 'method', 'class'].includes(symbol.kind)) continue;

      const line = symbol.startLine - 1; // Convert to 0-based
      if (line < 0 || line >= document.lineCount) continue;

      const range = new vscode.Range(line, 0, line, 0);

      // Get callers and callees
      const callers = this.store.getCallers(symbol.id);
      const callees = this.store.getCallees(symbol.id);

      // Caller lens
      if (callers.length > 0) {
        lenses.push(new vscode.CodeLens(range, {
          title: `↑ ${callers.length} caller${callers.length > 1 ? 's' : ''}`,
          command: 'codeatlas.showCallers',
          arguments: [symbol.id],
          tooltip: `Show ${callers.length} callers of ${symbol.name}`,
        }));
      }

      // Callee lens
      if (callees.length > 0) {
        lenses.push(new vscode.CodeLens(range, {
          title: `↓ ${callees.length} callee${callees.length > 1 ? 's' : ''}`,
          command: 'codeatlas.showCallees',
          arguments: [symbol.id],
          tooltip: `Show ${callees.length} callees of ${symbol.name}`,
        }));
      }

      // Layer badge
      const layerEmoji: Record<string, string> = {
        interface: '🔵',
        business: '🟢',
        data: '🟠',
        utility: '⚪',
        unknown: '❓',
      };
      const emoji = layerEmoji[symbol.layer] ?? '❓';
      lenses.push(new vscode.CodeLens(range, {
        title: `${emoji} ${symbol.layer}`,
        command: '',
        tooltip: `Layer: ${symbol.layer}`,
      }));
    }

    return lenses;
  }

  private getRelativePath(absolutePath: string): string {
    // Try to get relative path from workspace
    const workspaceFolder = vscode.workspace.workspaceFolders?.[0];
    if (workspaceFolder) {
      const workspacePath = workspaceFolder.uri.fsPath;
      if (absolutePath.startsWith(workspacePath)) {
        return absolutePath.slice(workspacePath.length + 1).replace(/\\/g, '/');
      }
    }
    return absolutePath;
  }
}

setStore(store: SQLiteStore) {
    this.store = store;
    this._onDidChangeCodeLenses.fire();
  }

refresh() {
    this._onDidChangeCodeLenses.fire();
  }

provideCodeLenses(document: vscode.TextDocument): vscode.CodeLens[] {
    if (!this.store) return [];

    const lenses: vscode.CodeLens[] = [];
    const filePath = this.getRelativePath(document.uri.fsPath);

    // Get symbols in this file
    const symbols = this.store.getSymbolsByFile(filePath);

    for (const symbol of symbols) {
      // Only show for functions, methods, classes
      if (!['function', 'method', 'class'].includes(symbol.kind)) continue;

      const line = symbol.startLine - 1; // Convert to 0-based
      if (line < 0 || line >= document.lineCount) continue;

      const range = new vscode.Range(line, 0, line, 0);

      // Get callers and callees
      const callers = this.store.getCallers(symbol.id);
      const callees = this.store.getCallees(symbol.id);

      // Caller lens
      if (callers.length > 0) {
        lenses.push(new vscode.CodeLens(range, {
          title: `↑ ${callers.length} caller${callers.length > 1 ? 's' : ''}`,
          command: 'codeatlas.showCallers',
          arguments: [symbol.id],
          tooltip: `Show ${callers.length} callers of ${symbol.name}`,
        }));
      }

      // Callee lens
      if (callees.length > 0) {
        lenses.push(new vscode.CodeLens(range, {
          title: `↓ ${callees.length} callee${callees.length > 1 ? 's' : ''}`,
          command: 'codeatlas.showCallees',
          arguments: [symbol.id],
          tooltip: `Show ${callees.length} callees of ${symbol.name}`,
        }));
      }

      // Layer badge
      const layerEmoji: Record<string, string> = {
        interface: '🔵',
        business: '🟢',
        data: '🟠',
        utility: '⚪',
        unknown: '❓',
      };
      const emoji = layerEmoji[symbol.layer] ?? '❓';
      lenses.push(new vscode.CodeLens(range, {
        title: `${emoji} ${symbol.layer}`,
        command: '',
        tooltip: `Layer: ${symbol.layer}`,
      }));
    }

    return lenses;
  }

private getRelativePath(absolutePath: string): string {
    // Try to get relative path from workspace
    const workspaceFolder = vscode.workspace.workspaceFolders?.[0];
    if (workspaceFolder) {
      const workspacePath = workspaceFolder.uri.fsPath;
      if (absolutePath.startsWith(workspacePath)) {
        return absolutePath.slice(workspacePath.length + 1).replace(/\\/g, '/');
      }
    }
    return absolutePath;
  }

interface AppState {
  cy: Core | null;
  activeLayers: Set<string>;
  selectedNode: string | null;
  graphData: { nodes: any[]; edges: any[] } | null;
  layoutType: 'cose' | 'breadthfirst' | 'circle';
}

async function init() {
  console.log('CodeAtlas Web initializing...');

  // Load graph data from API or local file
  state.graphData = await loadGraphData();

  if (state.graphData && state.graphData.nodes.length > 0) {
    initGraph(state.graphData);
    updateStats(state.graphData);
    hideEmptyState();
  }

  setupEventListeners();
}

async function loadGraphData(): Promise<{ nodes: any[]; edges: any[] } | null> {
  try {
    // Try fetching from API (when served by codeatlas serve)
    const response = await fetch('/api/graph');
    if (response.ok) {
      return await response.json();
    }
  } catch {
    // Not running via serve command
  }

  // Try loading from URL parameter
  const params = new URLSearchParams(window.location.search);
  const dataUrl = params.get('data');
  if (dataUrl) {
    try {
      const response = await fetch(dataUrl);
      return await response.json();
    } catch (err) {
      console.error('Failed to load graph data from URL:', err);
    }
  }

  return null;
}

function initGraph(data: { nodes: any[]; edges: any[] }) {
  const container = document.getElementById('cy')!;

  // Transform data to Cytoscape format
  const elements = [
    ...data.nodes.map(node => ({
      data: {
        id: node.id,
        label: node.name,
        kind: node.kind,
        layer: node.layer,
        file: node.filePath,
        line: node.startLine,
        exported: node.exported,
        complexity: node.complexity,
        weight: node.referenceCount ?? 1,
      },
      classes: `layer-${node.layer} kind-${node.kind}`,
    })),
    ...data.edges.map((edge, i) => ({
      data: {
        id: `e-${i}`,
        source: edge.sourceId,
        target: edge.targetId,
        kind: edge.kind,
        label: edge.kind,
      },
      classes: `rel-${edge.kind}`,
    })),
  ];

  state.cy = cytoscape({
    container,
    elements,

    style: [
      // Node base style
      {
        selector: 'node',
        style: {
          'label': 'data(label)',
          'text-valign': 'center',
          'text-halign': 'center',
          'font-size': '11px',
          'color': '#f1f5f9',
          'text-outline-color': '#0f172a',
          'text-outline-width': 2,
          'width': 'mapData(weight, 1, 50, 30, 80)',
          'height': 'mapData(weight, 1, 50, 30, 80)',
          'border-width': 2,
          'border-color': '#475569',
          'background-opacity': 0.9,
        },
      },
      // Layer colors
      ...Object.entries(LAYER_COLORS).map(([layer, color]) => ({
        selector: `node.layer-${layer}`,
        style: { 'background-color': color },
      })),
      // Kind shapes
      ...Object.entries(KIND_SHAPES).map(([kind, shape]) => ({
        selector: `node.kind-${kind}`,
        style: { 'shape': shape },
      })),
      // Edge base style
      {
        selector: 'edge',
        style: {
          'width': 1.5,
          'line-color': '#475569',
          'target-arrow-color': '#475569',
          'target-arrow-shape': 'triangle',
          'curve-style': 'bezier',
          'arrow-scale': 0.8,
          'opacity': 0.5,
        },
      },
      // Highlighted state
      {
        selector: 'node:selected',
        style: {
          'border-width': 3,
          'border-color': '#f59e0b',
          'z-index': 999,
        },
      },
      {
        selector: 'node.highlighted',
        style: {
          'border-width': 3,
          'border-color': '#f59e0b',
          'opacity': 1,
        },
      },
      {
        selector: 'edge.highlighted',
        style: {
          'width': 3,
          'line-color': '#f59e0b',
          'target-arrow-color': '#f59e0b',
          'opacity': 1,
        },
      },
      // Dimmed state
      {
        selector: 'node.dimmed',
        style: { 'opacity': 0.2 },
      },
      {
        selector: 'edge.dimmed',
        style: { 'opacity': 0.1 },
      },
    ],

    layout: {
      name: 'cose',
      animate: true,
      animationDuration: 800,
      nodeRepulsion: () => 8000,
      idealEdgeLength: () => 100,
      gravity: 0.25,
      numIter: 1000,
    } as any,

    // Interaction settings
    minZoom: 0.1,
    maxZoom: 5,
    wheelSensitivity: 0.3,
  });

  // Event handlers
  state.cy.on('tap', 'node', (evt: EventObject) => {
    selectNode(evt.target.id());
  });

  state.cy.on('tap', (evt: EventObject) => {
    if (evt.target === state.cy) {
      deselectAll();
    }
  });

  state.cy.on('dbltap', 'node', (evt: EventObject) => {
    focusOnNeighbors(evt.target.id());
  });
}

function selectNode(nodeId: string) {
  if (!state.cy) return;

  state.selectedNode = nodeId;
  const node = state.cy.getElementById(nodeId);
  const data = node.data();

  // Highlight node and neighbors
  state.cy.elements().removeClass('highlighted dimmed');
  const neighborhood = node.closedNeighborhood();
  state.cy.elements().addClass('dimmed');
  neighborhood.removeClass('dimmed').addClass('highlighted');

  // Update detail panel
  const panel = document.getElementById('detailPanel')!;
  panel.classList.remove('hidden');

  document.getElementById('detailName')!.textContent = data.label;

  const kindBadge = document.getElementById('detailKind')!;
  kindBadge.textContent = data.kind;

  const layerBadge = document.getElementById('detailLayer')!;
  layerBadge.textContent = data.layer;
  layerBadge.className = `badge layer-${data.layer}`;

  document.getElementById('detailFile')!.textContent = `${data.file}:${data.line}`;
  document.getElementById('detailComplexity')!.textContent = data.complexity ?? '-';

  // Count callers and callees
  const incoming = state.cy.edges(`[target = "${nodeId}"]`).length;
  const outgoing = state.cy.edges(`[source = "${nodeId}"]`).length;
  document.getElementById('detailCallers')!.textContent = String(incoming);
  document.getElementById('detailCallees')!.textContent = String(outgoing);
}

function deselectAll() {
  if (!state.cy) return;
  state.selectedNode = null;
  state.cy.elements().removeClass('highlighted dimmed');
  document.getElementById('detailPanel')!.classList.add('hidden');
}

function focusOnNeighbors(nodeId: string) {
  if (!state.cy) return;
  const node = state.cy.getElementById(nodeId);
  state.cy.fit(node.closedNeighborhood(), 50);
}

function updateLayerFilter() {
  if (!state.cy) return;

  state.cy.nodes().forEach(node => {
    const layer = node.data('layer');
    if (state.activeLayers.has(layer)) {
      node.style('display', 'element');
    } else {
      node.style('display', 'none');
    }
  });

  // Also hide edges connected to hidden nodes
  state.cy.edges().forEach(edge => {
    const sourceVisible = edge.source().style('display') !== 'none';
    const targetVisible = edge.target().style('display') !== 'none';
    edge.style('display', sourceVisible && targetVisible ? 'element' : 'none');
  });
}

function updateStats(data: { nodes: any[]; edges: any[] }) {
  const files = new Set(data.nodes.map(n => n.file ?? n.filePath));
  document.getElementById('statFiles')!.textContent = String(files.size);
  document.getElementById('statSymbols')!.textContent = String(data.nodes.length);
  document.getElementById('statRelationships')!.textContent = String(data.edges.length);

  // Layer counts
  const layerCounts: Record<string, number> = {};
  for (const node of data.nodes) {
    const layer = node.layer ?? 'unknown';
    layerCounts[layer] = (layerCounts[layer] ?? 0) + 1;
  }
  document.getElementById('countInterface')!.textContent = String(layerCounts.interface ?? 0);
  document.getElementById('countBusiness')!.textContent = String(layerCounts.business ?? 0);
  document.getElementById('countData')!.textContent = String(layerCounts.data ?? 0);
  document.getElementById('countUtility')!.textContent = String(layerCounts.utility ?? 0);
}

function hideEmptyState() {
  document.getElementById('emptyState')!.style.display = 'none';
}

function setupEventListeners() {
  // Search
  const searchInput = document.getElementById('searchInput') as HTMLInputElement;
  searchInput.addEventListener('input', (e) => {
    const query = (e.target as HTMLInputElement).value.toLowerCase();
    if (query.length < 2) {
      document.getElementById('searchResults')!.classList.add('hidden');
      return;
    }
    performSearch(query);
  });

  // Layer toggles
  document.querySelectorAll('.layer-toggle input').forEach(input => {
    input.addEventListener('change', (e) => {
      const layer = (e.target as HTMLInputElement).dataset.layer!;
      if ((e.target as HTMLInputElement).checked) {
        state.activeLayers.add(layer);
      } else {
        state.activeLayers.delete(layer);
      }
      updateLayerFilter();
    });
  });

  // Graph controls
  document.getElementById('btnZoomIn')?.addEventListener('click', () => {
    state.cy?.zoom(state.cy.zoom() * 1.3);
  });
  document.getElementById('btnZoomOut')?.addEventListener('click', () => {
    state.cy?.zoom(state.cy.zoom() / 1.3);
  });
  document.getElementById('btnFit')?.addEventListener('click', () => {
    state.cy?.fit(undefined, 50);
  });
  document.getElementById('btnLayout')?.addEventListener('click', () => {
    cycleLayout();
  });
  document.getElementById('btnFullscreen')?.addEventListener('click', () => {
    document.getElementById('graphContainer')?.requestFullscreen();
  });

  // Detail panel close
  document.getElementById('detailClose')?.addEventListener('click', deselectAll);

  // Detail panel actions
  document.getElementById('btnCopyPath')?.addEventListener('click', () => {
    const file = document.getElementById('detailFile')?.textContent;
    if (file) navigator.clipboard.writeText(file);
  });
}

function performSearch(query: string) {
  if (!state.cy || !state.graphData) return;

  const results = state.graphData.nodes.filter(n =>
    n.name?.toLowerCase().includes(query) ||
    n.label?.toLowerCase().includes(query) ||
    n.file?.toLowerCase().includes(query) ||
    n.filePath?.toLowerCase().includes(query)
  ).slice(0, 10);

  const container = document.getElementById('searchResults')!;
  if (results.length === 0) {
    container.innerHTML = '<div class="search-result-item">No results</div>';
    container.classList.remove('hidden');
    return;
  }

  container.innerHTML = results.map(r => `
    <div class="search-result-item" data-id="${r.id}">
      <strong>${r.name ?? r.label}</strong>
      <span style="color: var(--text-muted); margin-left: 8px;">(${r.kind})</span>
      <br>
      <small style="color: var(--text-muted);">${r.filePath ?? r.file}:${r.startLine ?? r.line}</small>
    </div>
  `).join('');
  container.classList.remove('hidden');

  // Click to focus
  container.querySelectorAll('.search-result-item').forEach(item => {
    item.addEventListener('click', () => {
      const id = (item as HTMLElement).dataset.id!;
      selectNode(id);
      const node = state.cy!.getElementById(id);
      state.cy!.animate({ fit: { eles: node, padding: 100 } } as any);
      container.classList.add('hidden');
    });
  });
}

function cycleLayout() {
  if (!state.cy) return;

  const layouts = ['cose', 'breadthfirst', 'circle'] as const;
  const currentIdx = layouts.indexOf(state.layoutType);
  state.layoutType = layouts[(currentIdx + 1) % layouts.length];

  const layoutOptions: Record<string, any> = {
    cose: { name: 'cose', animate: true, nodeRepulsion: () => 8000, idealEdgeLength: () => 100 },
    breadthfirst: { name: 'breadthfirst', animate: true, padding: 50 },
    circle: { name: 'circle', animate: true, padding: 50 },
  };

  state.cy.layout(layoutOptions[state.layoutType]).run();
}

async function getChokidar() {
  if (!chokidarModule) {
    chokidarModule = await import('chokidar');
  }
  return chokidarModule.default || chokidarModule;
}

interface WatcherOptions {
  /** Paths to watch (default: project root) */
  paths?: string[];
  /** Patterns to ignore */
  ignored?: (string | RegExp)[];
  /** Debounce delay in ms (default: 500) */
  debounceDelay?: number;
  /** Auto-scan on change (default: true) */
  autoScan?: boolean;
}

interface FileChangeEvent {
  type: 'add' | 'change' | 'unlink';
  path: string;
  timestamp: number;
}

class FileWatcher extends EventEmitter {
  private watcher: any | null = null;
  private scanner: ProjectScanner;
  private projectPath: string;
  private options: Required<WatcherOptions>;
  private debounceTimer: NodeJS.Timeout | null = null;
  private pendingChanges = new Map<string, FileChangeEvent>();
  private isScanning = false;

  constructor(
    projectPath: string,
    scanner: ProjectScanner,
    options: WatcherOptions = {},
  ) {
    super();
    this.projectPath = projectPath;
    this.scanner = scanner;
    this.options = {
      paths: options.paths ?? [projectPath],
      ignored: options.ignored ?? [
        '**/node_modules/**',
        '**/.git/**',
        '**/dist/**',
        '**/build/**',
        '**/.codeatlas/**',
        '**/*.min.js',
        '**/*.map',
      ],
      debounceDelay: options.debounceDelay ?? 500,
      autoScan: options.autoScan ?? true,
    };
  }

  /**
   * Start watching files
   */
  async start(): Promise<void> {
    if (this.watcher) {
      console.warn('FileWatcher already started');
      return;
    }

    const chokidar = await getChokidar();

    console.log(`\n👁️  Starting file watcher...`);
    console.log(`   Paths: ${this.options.paths.join(', ')}`);
    console.log(`   Debounce: ${this.options.debounceDelay}ms`);

    this.watcher = chokidar.watch(this.options.paths, {
      ignored: this.options.ignored,
      persistent: true,
      ignoreInitial: true,
      awaitWriteFinish: {
        stabilityThreshold: 100,
        pollInterval: 50,
      },
    });

    this.watcher
      .on('change', (path: string) => this.handleEvent('change', path))
      .on('add', (path: string) => this.handleEvent('add', path))
      .on('unlink', (path: string) => this.handleEvent('unlink', path))
      .on('error', (error: Error) => this.emit('error', error))
      .on('ready', () => {
        console.log('   ✅ Watching for changes...\n');
        this.emit('ready');
      });
  }

  /**
   * Stop watching files
   */
  async stop(): Promise<void> {
    if (this.debounceTimer) {
      clearTimeout(this.debounceTimer);
      this.debounceTimer = null;
    }

    if (this.watcher) {
      await this.watcher.close();
      this.watcher = null;
      console.log('👁️  File watcher stopped');
    }
  }

  /**
   * Get watcher status
   */
  isWatching(): boolean {
    return this.watcher !== null;
  }

  /**
   * Handle file change events
   */
  private handleEvent(type: 'add' | 'change' | 'unlink', filePath: string): void {
    const event: FileChangeEvent = {
      type,
      path: filePath,
      timestamp: Date.now(),
    };

    this.pendingChanges.set(filePath, event);
    this.emit('fileChange', event);

    // Debounce scanning
    if (this.debounceTimer) {
      clearTimeout(this.debounceTimer);
    }

    this.debounceTimer = setTimeout(() => {
      this.processChanges();
    }, this.options.debounceDelay);
  }

  /**
   * Process accumulated changes and trigger scan
   */
  private async processChanges(): Promise<void> {
    if (this.isScanning || this.pendingChanges.size === 0) {
      return;
    }

    this.isScanning = true;
    const changes = Array.from(this.pendingChanges.values());
    this.pendingChanges.clear();

    console.log(`\n📝 Detected ${changes.length} file changes`);

    // Group by change type
    const added = changes.filter(c => c.type === 'add');
    const modified = changes.filter(c => c.type === 'change');
    const deleted = changes.filter(c => c.type === 'unlink');

    if (added.length > 0) console.log(`   + ${added.length} added`);
    if (modified.length > 0) console.log(`   ~ ${modified.length} modified`);
    if (deleted.length > 0) console.log(`   - ${deleted.length} deleted`);

    if (this.options.autoScan) {
      try {
        this.emit('scanStart', changes);

        const result = await this.scanner.scan({
          projectPath: this.projectPath,
          full: false,
        });

        console.log(`   ✅ Scan complete in ${result.duration}ms`);
        console.log(`      ${result.symbolsFound} symbols, ${result.relationshipsFound} relationships\n`);

        this.emit('scanComplete', result);
        this.emit('update', result);
      } catch (error) {
        console.error('   ❌ Scan failed:', error);
        this.emit('error', error);
      } finally {
        this.isScanning = false;
      }
    } else {
      this.isScanning = false;
    }
  }
}

