interface ScanConfig {
  include?: string[];
  exclude?: string[];
  languages?: string[];
}

interface LayerConfig {
  interface?: { paths?: string[] };
  business?: { paths?: string[] };
  data?: { paths?: string[] };
  utility?: { paths?: string[] };
}

interface AIConfig {
  provider?: 'claude' | 'openai' | 'local';
  model?: string;
  apiKey?: string;
  baseUrl?: string;
  autoExplain?: boolean;
  batchSize?: number;
}

interface MCPConfig {
