  watchChanges?: boolean;
}

interface CodeAtlasConfig {
  name?: string;
  version?: string;
  scan?: ScanConfig;
  layers?: LayerConfig;
  ai?: AIConfig;
  mcp?: MCPConfig;
}

function loadConfig(projectPath: string): CodeAtlasConfig {
  const configPath = path.join(projectPath, '.codeatlas.yaml');
  const jsonConfigPath = path.join(projectPath, '.codeatlas.json');

  let config: CodeAtlasConfig = { ...DEFAULT_CONFIG };

  // Try YAML config
  if (fs.existsSync(configPath)) {
    try {
      const content = fs.readFileSync(configPath, 'utf-8');
      config = parseYAML(content);
      console.log(`Loaded config from ${configPath}`);
    } catch (error) {
      console.warn(`Failed to parse ${configPath}:`, error);
    }
  }
  // Try JSON config
  else if (fs.existsSync(jsonConfigPath)) {
    try {
      const content = fs.readFileSync(jsonConfigPath, 'utf-8');
      config = JSON.parse(content);
      console.log(`Loaded config from ${jsonConfigPath}`);
    } catch (error) {
      console.warn(`Failed to parse ${jsonConfigPath}:`, error);
    }
  }

  // Merge with defaults
  return mergeConfig(DEFAULT_CONFIG, config);
}

function parseYAML(content: string): CodeAtlasConfig {
  const config: CodeAtlasConfig = {};
  const lines = content.split('\n');
  let currentSection: string | null = null;
  let currentSubSection: string | null = null;

  for (const line of lines) {
    // Skip comments and empty lines
    if (line.trim().startsWith('#') || line.trim() === '') continue;

    // Detect section (2-space indent)
    const sectionMatch = line.match(/^(\w+):/);
    if (sectionMatch && !line.startsWith('  ')) {
      currentSection = sectionMatch[1];
      currentSubSection = null;
      continue;
    }

    // Detect subsection (4-space indent)
    const subSectionMatch = line.match(/^  (\w+):/);
    if (subSectionMatch && line.startsWith('  ') && !line.startsWith('    ')) {
      currentSubSection = subSectionMatch[1];
      continue;
    }

    // Parse key-value pairs
    const kvMatch = line.match(/^\s+(\w+):\s*(.+)/);
    if (kvMatch) {
      const key = kvMatch[1];
      let value: any = kvMatch[2].trim();

      // Parse value types
      if (value === 'true') value = true;
      else if (value === 'false') value = false;
      else if (value === 'null') value = null;
      else if (/^\d+$/.test(value)) value = parseInt(value, 10);
      else if (value.startsWith('[') && value.endsWith(']')) {
        // Array
        value = value.slice(1, -1).split(',').map((s: string) => s.trim().replace(/['"]/g, ''));
      }
      else if (value.startsWith('"') && value.endsWith('"')) {
        value = value.slice(1, -1);
      }
      else if (value.startsWith("'") && value.endsWith("'")) {
        value = value.slice(1, -1);
      }

      // Assign to config
      if (currentSection && currentSubSection) {
        if (!config[currentSection as keyof CodeAtlasConfig]) {
          (config as any)[currentSection] = {};
        }
        if (!(config[currentSection as keyof CodeAtlasConfig] as any)[currentSubSection]) {
          (config[currentSection as keyof CodeAtlasConfig] as any)[currentSubSection] = {};
        }
        (config[currentSection as keyof CodeAtlasConfig] as any)[currentSubSection][key] = value;
      } else if (currentSection) {
        if (!config[currentSection as keyof CodeAtlasConfig]) {
          (config as any)[currentSection] = {};
        }
        (config[currentSection as keyof CodeAtlasConfig] as any)[key] = value;
      }
    }
  }

  return config;
}

function mergeConfig(defaults: CodeAtlasConfig, user: CodeAtlasConfig): CodeAtlasConfig {
  const result = { ...defaults };

  for (const key of Object.keys(user) as Array<keyof CodeAtlasConfig>) {
    const userValue = user[key];
    const defaultValue = defaults[key];

    if (userValue === undefined) continue;

    if (typeof userValue === 'object' && userValue !== null && !Array.isArray(userValue)) {
      (result as any)[key] = { ...(defaultValue as any), ...userValue };
    } else {
      (result as any)[key] = userValue;
    }
  }

  return result;
}

