      }

      // Batch insert files
      const fileStmt = this.db.prepare(`
        INSERT INTO files (path, language, size, line_count, hash, parsed_at, metadata)
        VALUES (?, ?, ?, ?, ?, ?, ?)
        ON CONFLICT(path) DO UPDATE SET
