          hash = excluded.hash, parsed_at = excluded.parsed_at, metadata = excluded.metadata
      `);

      for (const file of graph.files.values()) {
        fileStmt.run([
          file.path, file.language, file.size, file.lineCount,
          file.hash, file.parsedAt ?? null, file.metadata ? JSON.stringify(file.metadata) : null,
        ]);
      }

      this.run('COMMIT');
    } catch (err) {
      this.run('ROLLBACK');
      throw err;
    }
    this.persist();
  }

addAnnotation(symbolId: string, userId: string, content: string, type: string = 'comment'): string {
    const id = `${symbolId}:${userId}:${Date.now()}`;
    this.run(
      'INSERT INTO annotations (id, symbol_id, user_id, content, type) VALUES (?, ?, ?, ?, ?)',
      [id, symbolId, userId, content, type]
    );
    this.persist();
    return id;
  }

getAnnotations(symbolId: string): any[] {
    return this.queryAll(
      'SELECT * FROM annotations WHERE symbol_id = ? ORDER BY created_at DESC',
      [symbolId]
    );
  }

getAnnotationsByUser(userId: string): any[] {
    return this.queryAll(
      'SELECT * FROM annotations WHERE user_id = ? ORDER BY created_at DESC',
      [userId]
    );
  }

updateAnnotation(id: string, content: string): void {
    this.run(
      'UPDATE annotations SET content = ?, updated_at = datetime(\'now\') WHERE id = ?',
      [content, id]
    );
    this.persist();
  }

deleteAnnotation(id: string): void {
    this.run('DELETE FROM annotations WHERE id = ?', [id]);
    this.persist();
  }

resolveAnnotation(id: string, resolved: boolean): void {
    this.run(
      'UPDATE annotations SET resolved = ?, updated_at = datetime(\'now\') WHERE id = ?',
      [resolved ? 1 : 0, id]
    );
    this.persist();
  }

getAnnotationCounts(): Map<string, number> {
    const rows = this.queryAll(
      'SELECT symbol_id, COUNT(*) as count FROM annotations GROUP BY symbol_id'
    );
    const counts = new Map<string, number>();
    for (const row of rows) {
      counts.set(row.symbol_id, row.count);
    }
    return counts;
  }

clear(): void {
    this.run('DELETE FROM relationships');
    this.run('DELETE FROM symbols');
    this.run('DELETE FROM files');
    this.persist();
  }

close(): void {
    this.persist();
    this.db.close();
  }

private persist(): void {
    if (this.dirty) {
      const data = this.db.export();
      const buffer = Buffer.from(data);
      fs.writeFileSync(this.dbPath, buffer);
      this.dirty = false;
    }
  }

private rowToRelationship(row: any): Relationship {
    return {
      id: row.id,
      sourceId: row.source_id,
      targetId: row.target_id,
      kind: row.kind as RelationshipKind,
      line: row.line,
      metadata: row.metadata ? JSON.parse(row.metadata) : undefined,
    };
  }

interface ScanOptions {
  /** Project root directory */
  projectPath: string;
  /** Full scan (ignore hash-based change detection) */
  full?: boolean;
  /** File glob patterns to include (default: all supported types) */
  include?: string[];
  /** File glob patterns to exclude */
  exclude?: string[];
  /** Progress callback */
  onProgress?: (current: number, total: number, file: string) => void;
  /** Enable AI analysis (default: false) */
  enableAI?: boolean;
}

interface ScanResult {
  filesScanned: number;
  filesSkipped: number;
  symbolsFound: number;
  relationshipsFound: number;
  languages: string[];
  duration: number;  // milliseconds
}

class ProjectScanner {
  private parser: CodeParser;
  private graphBuilder: GraphBuilder;
  private store: SQLiteStore;

  constructor(store: SQLiteStore) {
    this.parser = new CodeParser();
    this.graphBuilder = new GraphBuilder();
    this.store = store;
  }

  /**
   * Scan a project directory and build/update the code graph.
   */
  async scan(options: ScanOptions): Promise<ScanResult> {
    const startTime = Date.now();
    const { projectPath, full = false } = options;

    // Phase 1: Initialize parser
    await this.parser.init();

    // Phase 2: Discover files
    const files = await this.discoverFiles(projectPath, options);

    // Phase 3: Detect which files need (re-)parsing
    const { toParse, toSkip } = full
      ? { toParse: files, toSkip: [] as string[] }
      : this.detectChanges(files, projectPath);

    // Phase 4: Load required languages
    const languagesNeeded = new Set(
      toParse.map(f => detectLanguage(f)).filter(Boolean) as string[]
    );
    for (const lang of languagesNeeded) {
      await this.parser.loadLanguage(lang);
    }

    // Phase 5: Parse files (parallel for better performance)
    const parseResults = [];
    const fileInfoMap = new Map<string, FileInfo>();

    // Parse files in batches for parallel processing
    const BATCH_SIZE = 10;
    for (let i = 0; i < toParse.length; i += BATCH_SIZE) {
      const batch = toParse.slice(i, i + BATCH_SIZE);
      const batchResults = await Promise.all(
        batch.map(async (absolutePath, batchIndex) => {
          const relativePath = path.relative(projectPath, absolutePath);
          const globalIndex = i + batchIndex + 1;
          options.onProgress?.(globalIndex, toParse.length, relativePath);

          try {
            const sourceCode = fs.readFileSync(absolutePath, 'utf-8');
            const result = this.parser.parse(sourceCode, relativePath);

            // Compute file info
            const hash = crypto.createHash('sha256').update(sourceCode).digest('hex');
            const fileInfo: FileInfo = {
              path: relativePath,
              language: result.language,
              size: Buffer.byteLength(sourceCode),
              lineCount: sourceCode.split('\n').length,
              hash,
              parsedAt: new Date().toISOString(),
            };

            return { result, fileInfo };
          } catch (err) {
            console.warn(`Failed to parse ${relativePath}:`, err);
            return null;
          }
        })
      );

      // Collect results
      for (const item of batchResults) {
        if (item) {
          parseResults.push(item.result);
          fileInfoMap.set(item.fileInfo.path, item.fileInfo);
        }
      }
    }

    // Phase 6: Build graph
    const graph = this.graphBuilder.build(parseResults, fileInfoMap);

    // Phase 7: AI Analysis (optional)
    if (options.enableAI) {
      try {
        const config = loadConfig(projectPath);
        const aiConfig = getAIConfig(config);

        if (aiConfig.provider) {
          console.log(`\n🤖 Running AI analysis with ${aiConfig.provider}...`);
          const explainer = new ModuleExplainer({
            provider: aiConfig.provider,
            model: aiConfig.model,
            apiKey: aiConfig.apiKey,
            baseUrl: aiConfig.baseUrl,
          });

          // Generate summaries for symbols without them
          let explained = 0;
          for (const [id, symbol] of graph.symbols) {
            if (!symbol.aiSummary && symbol.sourceCode) {
              try {
                const summary = await explainer.explainSymbol(symbol);
                symbol.aiSummary = summary;
                explained++;

                // Respect batch size limit
                if (aiConfig.batchSize && explained >= aiConfig.batchSize) {
                  console.log(`   Reached batch limit (${aiConfig.batchSize})`);
                  break;
                }
              } catch (err) {
                console.warn(`   Failed to explain ${symbol.name}:`, err);
              }
            }
          }
          console.log(`   ✅ Generated ${explained} AI summaries`);
        }
      } catch (err) {
        console.warn('AI analysis failed:', err);
      }
    }

    // Phase 8: Persist
    if (!full) {
      // Incremental: only update changed files
      for (const filePath of toParse) {
        const relativePath = path.relative(projectPath, filePath);
        this.store.deleteSymbolsByFile(relativePath);
      }
    } else {
      this.store.clear();
    }
    this.store.saveGraph(graph);

    const duration = Date.now() - startTime;

    return {
      filesScanned: toParse.length,
      filesSkipped: toSkip.length,
      symbolsFound: graph.symbols.size,
      relationshipsFound: graph.relationships.length,
      languages: Array.from(languagesNeeded),
      duration,
    };
  }

  /**
   * Discover all parseable files in the project directory.
   * Respects .gitignore and custom include/exclude patterns.
   */
  private async discoverFiles(projectPath: string, options: ScanOptions): Promise<string[]> {
    // Load .gitignore
    const gitignorePath = path.join(projectPath, '.gitignore');
    const ig = ignore();

    // Always ignore common directories
    ig.add(['node_modules', '.git', 'dist', 'build', 'coverage', '.next', '.nuxt', '__pycache__', 'vendor', 'target']);

    if (fs.existsSync(gitignorePath)) {
      const gitignoreContent = fs.readFileSync(gitignorePath, 'utf-8');
      ig.add(gitignoreContent);
    }

    // Supported extensions
    const supportedExtensions = [
      'js', 'jsx', 'mjs', 'cjs',
      'ts', 'tsx',
      'py',
      'go',
      'rs',
      'java',
      'rb', 'php', 'cs',
      'c', 'h', 'cpp', 'hpp',
    ];

    const includePattern = options.include?.length
      ? options.include
      : [`**/*.{${supportedExtensions.join(',')}}`];

    const allFiles = await glob(includePattern, {
      cwd: projectPath,
      absolute: true,
      nodir: true,
      ignore: options.exclude ?? [],
    });

    // Filter through .gitignore
    return allFiles.filter(f => {
      const relative = path.relative(projectPath, f);
      return !ig.ignores(relative);
    });
  }

  /**
   * Detect which files have changed since last scan.
   * Returns files to parse and files to skip.
   */
  private detectChanges(files: string[], projectPath: string): { toParse: string[]; toSkip: string[] } {
    const toParse: string[] = [];
    const toSkip: string[] = [];

    for (const filePath of files) {
      const relativePath = path.relative(projectPath, filePath);
      const storedHash = this.store.getFileHash(relativePath);

      if (!storedHash) {
        // New file
        toParse.push(filePath);
        continue;
      }

      // Compute current hash
      const content = fs.readFileSync(filePath, 'utf-8');
      const currentHash = crypto.createHash('sha256').update(content).digest('hex');

      if (currentHash !== storedHash) {
        toParse.push(filePath);
      } else {
        toSkip.push(filePath);
      }
    }

    return { toParse, toSkip };
  }
}

