private checkCorrectness(symbol: Symbol): ReviewFinding[] {
    const findings: ReviewFinding[] = [];

    if (!symbol.sourceCode) return findings;

    // Check for TODO/FIXME/HACK
    const todoRegex = /(TODO|FIXME|HACK|XXX|WORKAROUND)\s*[:\-]?\s*(.*)/gi;
    let match;
    while ((match = todoRegex.exec(symbol.sourceCode)) !== null) {
      findings.push({
        severity: 'info',
        category: 'correctness',
        symbolId: symbol.id,
        symbolName: symbol.name,
        file: symbol.filePath,
        line: symbol.startLine,
        description: `Unresolved ${match[1]}: ${match[2].trim()}`,
      });
    }

    // Check for empty catch blocks
    if (symbol.sourceCode.match(/catch\s*\([^)]*\)\s*\{\s*\}/)) {
      findings.push({
        severity: 'warning',
        category: 'correctness',
        symbolId: symbol.id,
        symbolName: symbol.name,
        file: symbol.filePath,
        line: symbol.startLine,
        description: 'Empty catch block — errors are silently swallowed',
        suggestion: 'Add error logging or re-throw the error',
      });
    }

    // Check for deep nesting
    const lines = symbol.sourceCode.split('\n');
    let maxDepth = 0;
    let maxDepthLine = symbol.startLine;
    for (let i = 0; i < lines.length; i++) {
      const depth = (lines[i].match(/\{/g) || []).length - (lines[i].match(/\}/g) || []).length;
      if (depth > maxDepth) {
        maxDepth = depth;
        maxDepthLine = symbol.startLine + i;
      }
    }
    if (maxDepth > 4) {
      findings.push({
        severity: 'warning',
        category: 'correctness',
        symbolId: symbol.id,
        symbolName: symbol.name,
        file: symbol.filePath,
        line: maxDepthLine,
        description: `Deep nesting detected (depth: ${maxDepth}) — consider extracting functions`,
      });
    }

    return findings;
  }

private checkSecurity(symbol: Symbol): ReviewFinding[] {
    const findings: ReviewFinding[] = [];

    if (!symbol.sourceCode) return findings;

    // Check for eval()
    if (symbol.sourceCode.match(/\beval\s*\(/)) {
      findings.push({
        severity: 'error',
        category: 'security',
        symbolId: symbol.id,
        symbolName: symbol.name,
        file: symbol.filePath,
        line: symbol.startLine,
        description: 'Use of eval() detected — potential code injection risk',
        suggestion: 'Replace eval() with a safe alternative',
      });
    }

    // Check for innerHTML
    if (symbol.sourceCode.match(/\.innerHTML\s*=/)) {
      findings.push({
        severity: 'warning',
        category: 'security',
        symbolId: symbol.id,
        symbolName: symbol.name,
        file: symbol.filePath,
        line: symbol.startLine,
        description: 'Direct innerHTML assignment — potential XSS risk',
        suggestion: 'Use textContent or a sanitization library',
      });
    }

    // Check for hardcoded secrets
    const secretPatterns = [
      /(?:password|passwd|secret|api_?key|token|auth)\s*[:=]\s*['"][^'"]{8,}['"]/gi,
    ];
    for (const pattern of secretPatterns) {
      if (pattern.test(symbol.sourceCode)) {
        findings.push({
          severity: 'error',
          category: 'security',
          symbolId: symbol.id,
          symbolName: symbol.name,
          file: symbol.filePath,
          line: symbol.startLine,
          description: 'Potential hardcoded secret detected',
          suggestion: 'Move secrets to environment variables',
        });
      }
    }

    return findings;
  }

private checkPerformance(symbol: Symbol): ReviewFinding[] {
    const findings: ReviewFinding[] = [];

    if (!symbol.sourceCode) return findings;

    // Check for synchronous file operations (Node.js)
    if (symbol.sourceCode.match(/\bfs\.(readFileSync|writeFileSync|existsSync)\s*\(/)) {
      findings.push({
        severity: 'warning',
        category: 'perf',
        symbolId: symbol.id,
        symbolName: symbol.name,
        file: symbol.filePath,
        line: symbol.startLine,
        description: 'Synchronous file I/O detected — may block the event loop',
        suggestion: 'Use async alternatives (fs.promises or fs.readFile with callback)',
      });
    }

    // Check for nested loops
    const forLoopRegex = /for\s*\([^)]*\)\s*\{[^}]*for\s*\(/g;
    if (forLoopRegex.test(symbol.sourceCode)) {
      findings.push({
        severity: 'warning',
        category: 'perf',
        symbolId: symbol.id,
        symbolName: symbol.name,
        file: symbol.filePath,
        line: symbol.startLine,
        description: 'Nested loops detected — potential O(n²) complexity',
      });
    }

    // Check for large function body
    if (symbol.sourceCode) {
      const lineCount = symbol.sourceCode.split('\n').length;
      if (lineCount > 100) {
        findings.push({
          severity: 'info',
          category: 'perf',
          symbolId: symbol.id,
          symbolName: symbol.name,
          file: symbol.filePath,
          line: symbol.startLine,
          description: `Large function (${lineCount} lines) — consider breaking it up`,
        });
      }
    }

    return findings;
  }

private checkReadability(symbol: Symbol): ReviewFinding[] {
    const findings: ReviewFinding[] = [];

    if (!symbol.sourceCode) return findings;

    // Check for magic numbers
    const magicNumberRegex = /(?<!=\s*)(?<![\w.])\b(?!0\b|1\b|2\b|100\b)\d{3,}\b(?!\.\d)/g;
    let match;
    while ((match = magicNumberRegex.exec(symbol.sourceCode)) !== null) {
      // Skip common acceptable numbers
      const num = parseInt(match[0]);
      if ([1000, 1024, 60, 24, 365, 10000].includes(num)) continue;

      findings.push({
        severity: 'info',
        category: 'readability',
        symbolId: symbol.id,
        symbolName: symbol.name,
        file: symbol.filePath,
        line: symbol.startLine,
        description: `Magic number ${match[0]} — consider extracting to a named constant`,
      });
    }

    // Check for excessively long parameter lists
    const longParamRegex = /function\s+\w+\s*\(([^)]{100,})\)/;
    if (longParamRegex.test(symbol.sourceCode)) {
      findings.push({
        severity: 'info',
        category: 'readability',
        symbolId: symbol.id,
        symbolName: symbol.name,
        file: symbol.filePath,
        line: symbol.startLine,
        description: 'Long parameter list — consider using an options object',
      });
    }

    return findings;
  }

private async aiReview(
    symbols: Symbol[],
    focus: string[],
    options: {
      smart: boolean;
      tokenBudget?: number;
      staticFindings: StaticFinding[];
    },
  ): Promise<ReviewFinding[]> {
    if (!this.llmClient) return [];

    const findings: ReviewFinding[] = [];

    if (options.smart) {
      // Smart mode: use ContextBuilder for graph-aware context
      const context = this.contextBuilder.buildReviewContext(symbols, {
        maxTokens: options.tokenBudget ?? 4000,
        includeSource: 'signature',
        includeCallers: true,
        includeCallees: true,
        includeStaticFindings: true,
      }, options.staticFindings);

      const userPrompt = `## Changed Symbols (graph context)\n\n${context.codeContext}\n\n${context.staticFindings ? `\n${context.staticFindings}\n` : ''}\nReview for issues NOT covered by static analysis. Focus: ${focus.join(', ')}`;

      try {
        let response: string;
        if (this.llmClient.completeWithSystem) {
          response = await this.llmClient.completeWithSystem(context.systemPrompt, userPrompt);
        } else {
          response = await this.llmClient.complete(`${context.systemPrompt}\n\n${userPrompt}`);
        }
        const parsed = this.parseAIResponse(response, symbols);
        findings.push(...parsed);
      } catch (err) {
        console.error('Smart AI review failed:', err);
      }
    } else {
      // Traditional mode: send full source code
      const batchSize = 5;
      for (let i = 0; i < symbols.length; i += batchSize) {
        const batch = symbols.slice(i, i + batchSize);

        const codeContext = batch.map(s =>
          `### ${s.name} (${s.kind}) @ ${s.filePath}:${s.startLine}\n\`\`\`\n${s.sourceCode || '(no source)'}\n\`\`\``
        ).join('\n\n');

        const prompt = `You are a senior code reviewer. Analyze the following code changes and identify issues.

Focus areas: ${focus.join(', ')}

For each issue found, respond in this exact JSON format (one array):
[
  {
    "severity": "error|warning|info",
    "category": "security|perf|correctness|readability",
    "symbolName": "function/class name",
    "line": line_number,
    "description": "clear description of the issue",
    "suggestion": "optional fix suggestion"
  }
]

If no issues found, respond with an empty array: []

Code to review:
${codeContext}`;

        try {
          const response = await this.llmClient.complete(prompt);
          const parsed = this.parseAIResponse(response, batch);
          findings.push(...parsed);
        } catch (err) {
          console.error(`AI review failed for batch ${i}:`, err);
        }
      }
    }

    return findings;
  }

private parseAIResponse(response: string, symbols: Symbol[]): ReviewFinding[] {
    try {
      // Extract JSON from response (handle markdown code blocks)
      const jsonMatch = response.match(/\[[\s\S]*\]/);
      if (!jsonMatch) return [];

      const items = JSON.parse(jsonMatch[0]);
      if (!Array.isArray(items)) return [];

      return items.map((item: any) => {
        // Find the matching symbol
        const symbol = symbols.find(s => s.name === item.symbolName) || symbols[0];

        return {
          severity: item.severity || 'info',
          category: item.category || 'correctness',
          symbolId: symbol?.id || '',
          symbolName: item.symbolName || symbol?.name || 'unknown',
          file: symbol?.filePath || '',
          line: item.line || symbol?.startLine || 0,
          description: item.description || '',
          suggestion: item.suggestion,
        };
      });
    } catch {
      return [];
    }
  }

private buildSummary(findings: ReviewFinding[], reviewedCount: number, impactSize: number, smart: boolean, tokenBudget?: number): string {
    const parts: string[] = [];

    const errors = findings.filter(f => f.severity === 'error');
    const warnings = findings.filter(f => f.severity === 'warning');
    const infos = findings.filter(f => f.severity === 'info');

    parts.push(`🔍 Code Review Summary`);
    parts.push('═'.repeat(40));
    parts.push(`Reviewed: ${reviewedCount} symbols | Impact scope: ${impactSize} symbols`);
    parts.push(`Mode: ${smart ? '🧠 Smart (graph context)' : '📝 Traditional (full source)'}`);
    if (smart) {
      parts.push(`Token budget: ${tokenBudget ?? 4000} tokens`);
    }
    parts.push(`Findings: ${errors.length} errors, ${warnings.length} warnings, ${infos.length} info`);

    if (errors.length > 0) {
      parts.push(`\n❌ Errors:`);
      for (const f of errors) {
        parts.push(`  [${f.category}] ${f.symbolName}: ${f.description}`);
        if (f.suggestion) parts.push(`    💡 ${f.suggestion}`);
      }
    }

    if (warnings.length > 0) {
      parts.push(`\n⚠️  Warnings:`);
      for (const f of warnings) {
        parts.push(`  [${f.category}] ${f.symbolName}: ${f.description}`);
        if (f.suggestion) parts.push(`    💡 ${f.suggestion}`);
      }
    }

    if (infos.length > 0) {
      parts.push(`\nℹ️  Info:`);
      for (const f of infos.slice(0, 10)) {
        parts.push(`  [${f.category}] ${f.symbolName}: ${f.description}`);
      }
      if (infos.length > 10) {
        parts.push(`  ... and ${infos.length - 10} more`);
      }
    }

    if (findings.length === 0) {
      parts.push('\n✅ No issues found — code looks good!');
    }

    return parts.join('\n');
  }

interface LLMConfig {
  provider: 'claude' | 'openai' | 'local';
  model?: string;
  apiKey?: string;
  baseUrl?: string;    // For local models (Ollama, etc.)
  maxTokens?: number;
}

interface ExplainOptions {
  /** Include source code in the explanation context */
  includeSource?: boolean;
  /** Include relationship info */
  includeRelationships?: boolean;
  /** Language for the explanation (default: Chinese) */
  language?: string;
}

class ModuleExplainer {
  private config: LLMConfig;
  private client: LLMClient | null = null;
  private contextBuilder: ContextBuilder | null = null;

  constructor(config: LLMConfig, store?: any) {
    this.config = config;
    this.initClient();
    if (store) {
      this.contextBuilder = new ContextBuilder(store);
    }
  }

  private initClient(): void {
    const baseClient = createLLMClient(this.config);
    if (baseClient) {
      this.client = new CachedLLMClient(baseClient);
    }
  }

  /**
   * Generate an explanation for a module (file or group of related symbols).
   */
  async explainModule(
    symbols: Symbol[],
    relationships: Relationship[],
    options: ExplainOptions = {},
  ): Promise<string> {
    if (!this.client) {
      return this.getFallbackMessage('module');
    }

    const context = this.buildContext(symbols, relationships, options);

    const prompt = `你是一个资深代码分析师。请分析以下代码模块，回答：

1. **核心职责**：这个模块做什么？（一句话概括）
2. **关键接口**：对外暴露了哪些重要的函数/类/方法？
3. **依赖关系**：它依赖了哪些其他模块？
4. **设计模式**：使用了什么设计模式或架构风格？
5. **潜在问题**：有没有明显的代码味道或改进空间？

请用简洁自然的语言回答，避免堆砌技术术语。

---

${context}`;

    try {
      return await this.client.complete(prompt);
    } catch (error) {
      console.error('LLM error:', error);
      return this.getFallbackMessage('module', error);
    }
  }

  /**
   * Generate an explanation for a single symbol.
   * Uses ai_summary when available (saves ~90% tokens).
   */
  async explainSymbol(symbol: Symbol): Promise<string> {
    if (!this.client) {
      return this.getFallbackMessage('symbol');
    }

    // If we have a store-backed context builder, use graph context
    if (this.contextBuilder) {
      const context = this.contextBuilder.buildExplainContext([symbol], {
        includeSource: !symbol.aiSummary, // Only include source if no AI summary
      });

      const userPrompt = `请用中文简洁解释这个${symbol.kind}的核心功能（1-3 句话）。\n\n${context.userContext}`;

      try {
        if (this.client.completeWithSystem) {
          return await this.client.completeWithSystem(context.systemPrompt, userPrompt);
        }
        return await this.client.complete(`${context.systemPrompt}\n\n${userPrompt}`);
      } catch (error) {
        console.error('LLM error:', error);
        return this.getFallbackMessage('symbol', error);
      }
    }

    // Fallback: use ai_summary if available, otherwise source code
    const codeSection = symbol.aiSummary
      ? `AI 摘要: ${symbol.aiSummary}`
      : `代码:\n\`\`\`\n${symbol.sourceCode ?? '(source not available)'}\n\`\`\``;

    const prompt = `请用中文简洁解释这段代码的作用：

类型: ${symbol.kind}
名称: ${symbol.name}
文件: ${symbol.filePath}
层级: ${symbol.layer}

${codeSection}

请用 1-3 句话解释这个${symbol.kind}的核心功能。`;

    try {
      return await this.client.complete(prompt);
    } catch (error) {
      console.error('LLM error:', error);
      return this.getFallbackMessage('symbol', error);
    }
  }

  /**
   * Semantic search: translate a natural language query to relevant symbols.
   * Optimized: uses FTS5 pre-filtering to reduce token usage by ~90%.
   */
  async semanticSearch(query: string, allSymbols: Symbol[]): Promise<Symbol[]> {
    if (!this.client) {
      console.warn('LLM not configured for semantic search');
      return [];
    }

    // Smart approach: pre-filter using FTS5 keyword search, then LLM ranks
    // Extract keywords from query (split on spaces, take meaningful words)
    const keywords = query.split(/\s+/).filter(w => w.length > 2);

    // Find candidates using name/docComment matching (cheap, local)
    const candidateSet = new Map<string, Symbol>();
    for (const symbol of allSymbols) {
      const nameMatch = keywords.some(kw => symbol.name.toLowerCase().includes(kw.toLowerCase()));
      const docMatch = symbol.docComment && keywords.some(kw => symbol.docComment!.toLowerCase().includes(kw.toLowerCase()));
      const summaryMatch = symbol.aiSummary && keywords.some(kw => symbol.aiSummary!.toLowerCase().includes(kw.toLowerCase()));

      if (nameMatch || docMatch || summaryMatch) {
        candidateSet.set(symbol.id, symbol);
      }
    }

    // If we found candidates, use those; otherwise fall back to all symbols
    const candidates = candidateSet.size > 0
      ? Array.from(candidateSet.values())
      : allSymbols;

    // Limit candidates to top 50 by relevance (name match > doc match > summary match)
    const scored = candidates.map(s => ({
      symbol: s,
      score: (keywords.some(kw => s.name.toLowerCase().includes(kw.toLowerCase())) ? 3 : 0) +
             (s.docComment && keywords.some(kw => s.docComment!.toLowerCase().includes(kw.toLowerCase())) ? 2 : 0) +
             (s.aiSummary && keywords.some(kw => s.aiSummary!.toLowerCase().includes(kw.toLowerCase())) ? 1 : 0),
    })).sort((a, b) => b.score - a.score).slice(0, 50);

    // Send only top candidates to LLM (not all symbols)
    const prompt = `用户想找到: "${query}"

以下是项目中可能相关的符号（已按相关性预筛选）：
${scored.map(({ symbol: s, score }) => `- ${s.name} (${s.kind}, ${s.layer}) @ ${s.filePath} [relevance: ${score}]`).join('\n')}

请从上面的列表中选出最相关的 5-10 个符号，只返回它们的名称，每行一个。`;

    try {
      const response = await this.client.complete(prompt);
      const relevantNames = response.split('\n').map(l => l.trim().replace(/^- /, '')).filter(Boolean);
      return scored.map(({ symbol: s }) => s).filter(s => relevantNames.includes(s.name));
    } catch (error) {
      console.error('LLM semantic search error:', error);
      return [];
    }
  }

  /** Build context string for LLM prompts */
  private buildContext(
    symbols: Symbol[],
    relationships: Relationship[],
    options: ExplainOptions,
  ): string {
    const parts: string[] = [];

    // Symbol overview
    parts.push('## 符号列表\n');
    for (const s of symbols) {
      parts.push(`- ${s.name} (${s.kind}, layer: ${s.layer}) [${s.filePath}:${s.startLine}-${s.endLine}]`);
      if (s.docComment) {
        parts.push(`  注释: ${s.docComment.slice(0, 200)}`);
      }
    }

    // Relationships
    if (options.includeRelationships !== false && relationships.length > 0) {
      parts.push('\n## 关系\n');
      for (const r of relationships) {
        parts.push(`- ${r.sourceId} --${r.kind}--> ${r.targetId}`);
      }
    }

    // Source code
    if (options.includeSource !== false) {
      parts.push('\n## 源代码\n');
      for (const s of symbols) {
        if (s.sourceCode) {
          parts.push(`### ${s.name}\n\`\`\`\n${s.sourceCode}\n\`\`\`\n`);
        }
      }
    }

    return parts.join('\n');
  }

  /** Get fallback message when LLM is not configured */
  private getFallbackMessage(type: 'module' | 'symbol', error?: any): string {
    const errorMsg = error ? ` Error: ${error.message}` : '';
    return `[AI ${type} explanation not available. Configure LLM provider in .codeatlas.yaml${errorMsg}]`;
  }
}

