async function infoCommand(symbolId: string) {
  const store = await SQLiteStore.create({
    dbPath: path.join(process.cwd(), '.codeatlas', 'db.sqlite'),
  });

  try {
    // Try multiple ID formats (Windows path handling)
    const normalizedId = symbolId.replace(/\\/g, '/');
    let symbol = store.getSymbol(normalizedId);

    if (!symbol) {
      // Try with original ID
      symbol = store.getSymbol(symbolId);
    }

    if (!symbol) {
      // Try with backslashes (Windows)
      const backslashId = normalizedId.replace(/\//g, '\\');
      symbol = store.getSymbol(backslashId);
    }

    if (!symbol) {
      // Search by name as fallback
      const results = store.searchSymbols(symbolId, { limit: 20 });

      if (results.length === 0) {
        console.log(`\n❌ Symbol "${symbolId}" not found\n`);
        console.log('  Tips:');
        console.log('  - Make sure you have scanned the project: codeatlas scan');
        console.log('  - Use codeatlas search to find symbols');
        console.log('  - ID format: filePath:name:startLine (e.g., src/index.ts:main:1)\n');
        return;
      }

      if (results.length === 1) {
        symbol = results[0];
      } else {
        // Smart matching: prefer class/function over variable
        const exactNameMatch = results.filter(s => s.name === symbolId);
        const preferred = exactNameMatch.length > 0 ? exactNameMatch : results;

        // Priority: class > function > method > interface > others
        const priority: Record<string, number> = {
          class: 1, function: 2, method: 3, interface: 4,
          type: 5, enum: 6, variable: 10, constant: 11,
        };

        preferred.sort((a, b) => (priority[a.kind] ?? 99) - (priority[b.kind] ?? 99));
        symbol = preferred[0];

        // Show warning if multiple matches
        if (preferred.length > 1) {
          console.log(`\n⚠️  Multiple matches found, showing best match (${symbol.kind}):\n`);
          console.log(`  Selected: ${symbol.name} (${symbol.kind}) @ ${symbol.filePath}:${symbol.startLine}`);
          console.log(`  Other matches:`);
          for (const s of preferred.slice(1, 5)) {
            console.log(`    - ${s.name} (${s.kind}) @ ${s.filePath}:${s.startLine}`);
          }
          if (preferred.length > 5) {
            console.log(`    ... and ${preferred.length - 5} more`);
          }
          console.log();
        }
      }
    }

    // Display symbol info
    const layerEmoji: Record<string, string> = {
      interface: '🔵',
      business: '🟢',
      data: '🟠',
      utility: '⚪',
      unknown: '❓',
    };

    console.log(`\n${layerEmoji[symbol.layer] ?? '❓'} Symbol: ${symbol.name}`);
    console.log('─'.repeat(50));
    console.log(`  ID:         ${symbol.id}`);
    console.log(`  Kind:       ${symbol.kind}`);
    console.log(`  Layer:      ${symbol.layer}`);
    console.log(`  File:       ${symbol.filePath}:${symbol.startLine}-${symbol.endLine}`);
    console.log(`  Language:   ${symbol.language}`);
    console.log(`  Exported:   ${symbol.exported ? 'Yes' : 'No'}`);

    if (symbol.complexity !== undefined) {
      console.log(`  Complexity: ${symbol.complexity}`);
    }

    if (symbol.docComment) {
      console.log(`\n  📝 Documentation:`);
      console.log(`  ${symbol.docComment}`);
    }

    if (symbol.aiSummary) {
      console.log(`\n  🤖 AI Summary:`);
      console.log(`  ${symbol.aiSummary}`);
    }

    if (symbol.sourceCode) {
      console.log(`\n  💻 Source Code:`);
      console.log('  ' + '─'.repeat(46));
      const lines = symbol.sourceCode.split('\n');
      for (const line of lines.slice(0, 20)) {
        console.log(`  │ ${line}`);
      }
      if (lines.length > 20) {
        console.log(`  │ ... (${lines.length - 20} more lines)`);
      }
      console.log('  ' + '─'.repeat(46));
    }

    // Show relationships
    const outgoing = store.getRelationshipsFrom(symbol.id);
    const incoming = store.getRelationshipsTo(symbol.id);

    if (outgoing.length > 0) {
      console.log(`\n  🔗 Outgoing Relationships (${outgoing.length}):`);
      for (const rel of outgoing.slice(0, 10)) {
        const target = store.getSymbol(rel.targetId);
        console.log(`     → ${rel.kind}: ${target?.name ?? rel.targetId}`);
      }
      if (outgoing.length > 10) {
        console.log(`     ... and ${outgoing.length - 10} more`);
      }
    }

    if (incoming.length > 0) {
      console.log(`\n  🔗 Incoming Relationships (${incoming.length}):`);
      for (const rel of incoming.slice(0, 10)) {
        const source = store.getSymbol(rel.sourceId);
        console.log(`     ← ${rel.kind}: ${source?.name ?? rel.sourceId}`);
      }
      if (incoming.length > 10) {
        console.log(`     ... and ${incoming.length - 10} more`);
      }
    }

    console.log();
  } finally {
    store.close();
  }
}

async function guardCommand(options: {
  format?: string;
  install?: boolean;
  maxDepth?: string;
  noCircular?: boolean;
}) {
  // Handle --install (generate git hook)
  if (options.install) {
    installHook();
    return;
  }

  const store = await SQLiteStore.create({
    dbPath: path.join(process.cwd(), '.codeatlas', 'db.sqlite'),
  });

  try {
    // Load guard config from .codeatlas.yaml if available
    const projectConfig = loadConfig(process.cwd());
    const guardConfig: GuardConfig = {
      ...(projectConfig as any).guard,
      maxImpactDepth: parseInt(options.maxDepth || '3'),
      forbidCircular: options.noCircular !== false,
    };

    const analyzer = new GuardAnalyzer(store, guardConfig);

    // Run full check
    const result = analyzer.check();

    // Also check impact for changed files
    const changedFiles = getChangedFiles();
    if (changedFiles.length > 0) {
      const impactViolations = analyzer.checkImpact(changedFiles);
      result.violations.push(...impactViolations);
      result.passed = result.violations.filter(v => v.severity === 'error').length === 0;
      result.summary = buildFullSummary(result.passed, result.violations, changedFiles.length);
    }

    if (options.format === 'json') {
      console.log(JSON.stringify(result, null, 2));
      process.exit(result.passed ? 0 : 1);
      return;
    }

    console.log(result.summary);
    process.exit(result.passed ? 0 : 1);

  } finally {
    store.close();
  }
}

function getChangedFiles(): string[] {
  try {
    const output = execSync('git diff --name-only HEAD 2>/dev/null || git diff --name-only 2>/dev/null || git ls-files --others --exclude-standard', {
      encoding: 'utf-8',
      cwd: process.cwd(),
    });
    return output.split('\n').map(f => f.trim()).filter(f => f.length > 0);
  } catch {
    return [];
  }
}

function buildFullSummary(passed: boolean, violations: any[], changedCount: number): string {
  const parts: string[] = [];

  if (passed) {
    parts.push('✅ All architecture checks passed!');
  } else {
    parts.push('❌ Architecture checks FAILED');
  }

  parts.push('═'.repeat(40));
  parts.push(`Changed files: ${changedCount}`);

  const errors = violations.filter((v: any) => v.severity === 'error');
  const warnings = violations.filter((v: any) => v.severity === 'warning');

  if (errors.length > 0) {
    parts.push(`\n🚫 Errors (${errors.length}):`);
    for (const v of errors) {
      parts.push(`  [${v.rule}] ${v.message}`);
    }
  }

  if (warnings.length > 0) {
    parts.push(`\n⚠️  Warnings (${warnings.length}):`);
    for (const v of warnings) {
      parts.push(`  [${v.rule}] ${v.message}`);
    }
  }

  return parts.join('\n');
}

function installHook() {
  const hookDir = path.join(process.cwd(), '.git', 'hooks');
  const hookPath = path.join(hookDir, 'pre-commit');

  if (!fs.existsSync(hookDir)) {
    console.log('❌ Not a git repository (no .git/hooks directory)');
    return;
  }

  const hookContent = `#!/bin/sh
# CodeAtlas architecture gate - auto-generated
# Run: codeatlas guard --install to regenerate

echo "🔍 Running CodeAtlas architecture checks..."
codeatlas guard --format text
exit $?
`;

  fs.writeFileSync(hookPath, hookContent, { mode: 0o755 });
  console.log('✅ Pre-commit hook installed at .git/hooks/pre-commit');
  console.log('   It will run "codeatlas guard" before each commit.');
}

async function flowCommand(
  entrySymbol: string,
  options: { depth?: string; format?: string }
) {
  const depth = parseInt(options.depth || '5');
  const format = options.format || 'text';

  const store = await SQLiteStore.create({
    dbPath: path.join(process.cwd(), '.codeatlas', 'db.sqlite'),
  });

  try {
    // Find the entry symbol
    const results = store.searchSymbols(entrySymbol, { limit: 5 });

    if (results.length === 0) {
      console.log(`\n❌ Symbol "${entrySymbol}" not found\n`);
      return;
    }

    // Use first result if exact match not found
    const entry = results.find(s => s.name === entrySymbol) ?? results[0];

    console.log(`\n📞 Tracing call chain for: ${entry.name}`);
    console.log(`   Max depth: ${depth}\n`);

    const analyzer = new FlowAnalyzer(store, depth);
    const result = analyzer.trace(entry.id);

    if (!result) {
      console.log('❌ Could not trace call chain');
      return;
    }

    if (format === 'mermaid') {
      console.log(FlowAnalyzer.formatAsMermaid(result));
    } else {
      console.log(FlowAnalyzer.formatAsText(result));
    }
  } finally {
    store.close();
  }
}

async function docCommand(options: {
  output?: string;
  source?: boolean;
  diagrams?: boolean;
  granularity?: string;
}) {
  const store = await SQLiteStore.create({
    dbPath: path.join(process.cwd(), '.codeatlas', 'db.sqlite'),
  });

  try {
    const exporter = new DocExporter(store);
    const result = await exporter.export(process.cwd(), {
      outputDir: options.output ? path.resolve(options.output) : undefined,
      includeSource: options.source !== false,
      includeDiagrams: options.diagrams !== false,
      granularity: (options.granularity as 'file' | 'module') || 'file',
    });

    console.log(result.summary);

  } finally {
    store.close();
  }
}

async function depsCommand(options: {
  format?: string;
  circular?: boolean;
}) {
  const store = await SQLiteStore.create({
    dbPath: path.join(process.cwd(), '.codeatlas', 'db.sqlite'),
  });

  try {
    const analyzer = new DepAnalyzer(store, process.cwd());
    const result = analyzer.analyze();

    if (options.circular) {
      // Only show circular dependencies
      if (result.circular.length === 0) {
        console.log('\n✅ No circular dependencies found\n');
      } else {
        console.log(`\n🔄 Circular Dependencies (${result.circular.length}):\n`);
        for (const c of result.circular) {
          console.log(`  ${c.chain.join(' → ')}`);
        }
      }
      return;
    }

    if (options.format === 'json') {
      console.log(JSON.stringify(result, null, 2));
      return;
    }

    // Default: pretty print
    console.log(result.summary);

  } finally {
    store.close();
  }
}

async function coverageCommand(options: { symbol?: string; format?: string }) {
  const store = await SQLiteStore.create({
    dbPath: path.join(process.cwd(), '.codeatlas', 'db.sqlite'),
  });

  try {
    const analyzer = new CoverageAnalyzer(store);

    if (options.symbol) {
      // Show coverage for specific symbol
      const results = store.searchSymbols(options.symbol, { limit: 5 });

      if (results.length === 0) {
        console.log(`\n❌ Symbol "${options.symbol}" not found\n`);
        return;
      }

      const symbol = results.find(s => s.name === options.symbol) ?? results[0];
      const report = analyzer.analyze();
      const detail = report.coverageDetails.find(c => c.symbol.id === symbol.id);

      if (detail) {
        console.log(`\n📊 Coverage for ${symbol.name}:`);
        console.log('─'.repeat(40));
        console.log(`  Has test: ${detail.hasTest ? '✅ Yes' : '❌ No'}`);
        if (detail.testFiles.length > 0) {
          console.log('  Test files:');
          for (const f of detail.testFiles) {
            console.log(`    - ${f}`);
          }
        }
        if (detail.testSymbolNames.length > 0) {
          console.log('  Test functions:');
          for (const n of detail.testSymbolNames) {
            console.log(`    - ${n}`);
          }
        }
      }
    } else {
      // Show full coverage report
      const report = analyzer.analyze();
      console.log(CoverageAnalyzer.formatReport(report));
    }
  } finally {
    store.close();
  }
}

async function askCommand(question: string) {
  const store = await SQLiteStore.create({
    dbPath: path.join(process.cwd(), '.codeatlas', 'db.sqlite'),
  });

  try {
    console.log(`\n❓ Question: ${question}\n`);

    // Try to load AI config for better answers
    let explainer: ModuleExplainer | undefined;
    try {
      const config = loadConfig(process.cwd());
      const aiConfig = getAIConfig(config);
      if (aiConfig.provider) {
        explainer = new ModuleExplainer({
          provider: aiConfig.provider,
          model: aiConfig.model,
          apiKey: aiConfig.apiKey,
          baseUrl: aiConfig.baseUrl,
        });
      }
    } catch {
      // No AI config, use structured answers
    }

    const analyzer = new AskAnalyzer(store, explainer);
    const result = await analyzer.answer(question);

    // Display results
    console.log('📖 Answer:');
    console.log('─'.repeat(50));
    console.log(result.answer);
    console.log('─'.repeat(50));

    // Show relevant symbols
    if (result.symbols.length > 0) {
      console.log(`\n📎 Referenced symbols (${result.symbols.length}):`);
      for (const symbol of result.symbols.slice(0, 5)) {
        console.log(`   - ${symbol.name} (${symbol.kind}) @ ${symbol.filePath}:${symbol.startLine}`);
      }
    }

    // Show confidence
    const confidence = Math.round(result.confidence * 100);
    console.log(`\n🎯 Confidence: ${confidence}%`);

    if (confidence < 50) {
      console.log('   (Low confidence - try rephrasing or be more specific)');
    }
    console.log();
  } finally {
    store.close();
  }
}
